mapper.select:
select
    concat(
        date_format(ds.start_time, '%Y-%m-%d %H:%i'),
        '至',
        date_format(ds.end_time, '%Y-%m-%d %H:%i')
    ) as SYJSSJ,
    case
        when nullif(#{cjid}, '') is not null then #{cjid}
        else coalesce(v.venue_name, cast(ds.venue_id as char))
    end as CJID
from duty_schedule ds
left join venue v on ds.venue_id = v.venue_id

    ds.start_time < #{queryEndTime}
    and ds.end_time >= #{queryStartTime}

        and (
            v.venue_name = #{cjid}
            or cast(ds.venue_id as char) = #{cjid}
        )


group by SYJSSJ, CJID
order by min(ds.start_time) asc, CJID asc
